const body = $input.first().json.body;
const imageUrl = (body?.image_url || '').trim();
const productName = (body?.product_name || '').trim();
const category = (body?.category || '').trim();
if (!imageUrl) throw new Error('image_url es requerido');
if (!imageUrl.startsWith('http')) throw new Error('image_url invalida: ' + imageUrl.substring(0, 80));
return [{ json: { imageUrl, productName, category } }];

const response = $input.first().json;
const d = response;
const parts = [];
if (d.garment_type) parts.push(d.garment_type + (d.silhouette ? ' de silueta ' + d.silhouette : ''));
if (d.primary_color) parts.push('Color principal: ' + d.primary_color);
if (d.secondary_colors?.length) parts.push('Colores secundarios: ' + d.secondary_colors.join(', '));
if (d.patterns) parts.push('Estampado: ' + d.patterns);
if (d.materials) parts.push('Material: ' + d.materials);
if (d.fit) parts.push('Fit: ' + d.fit);
if (d.accessory_type) parts.push('Tipo: ' + d.accessory_type);
if (d.placement) parts.push('Posicion: ' + d.placement);
if (d.material) parts.push('Material: ' + d.material);
if (d.footwear_type) parts.push('Tipo: ' + d.footwear_type);
if (d.heel_height) parts.push('Taco: ' + d.heel_height);
const category = d.product_type;
const enrichedPrompt = response.enrichedPrompt || '';
return [{ json: { description: parts.join('. ') + '.', category, enrichedPrompt } }];
